+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
?/g, '\
');
+}
+
+function shouldStrip(line: string, options: NormalizedErrorStackOptions): boolean {
+  const node = line.includes('node:internal');
+  const superjson =
+    line.includes('src/transformer.ts') ||
+    line.includes('src/plainer.ts') ||
+    line.includes('src/index.ts');
+  return (
+    (options.stripInternalFrames === 'node' && node) ||
+    (options.stripInternalFrames === 'superjson' && superjson) ||
+    (options.stripInternalFrames === 'node_and_superjson' && (node || superjson))
+  );
+}
+
+function redact(line: string, options: NormalizedErrorStackOptions): string {
+  if (options.redactPaths === 'strip_cwd') {
+    const cwd = process.cwd().replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&');
+    return line.replace(new RegExp(cwd.replace(/\\\\/g, '[\\\\\\\\/]'), 'g'), '');
+  }
+  if (options.redactPaths === 'basename') {
+    return line.replace(/(?:[A-Za-z]:)?(?:[\\\\/][^\\\\/():\\s]+)+(?=:\\d+(?::\\d+)?)/g, path => {
+      const parts = path.split(/[\\\\/]/);
+      return parts[parts.length - 1];
+    });
+  }
+  return line;
+}
+
+function processLines(stack: string, options: NormalizedErrorStackOptions, frames: boolean): string[] {
+  const normalized = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
+  let lines = normalized.split('\
');
+  if (options.trimLeadingWhitespace) {
+    lines = lines.map((line, index) => (index === 0 ? line : line.replace(/^\\s+/, '')));
+  }
+  if (frames) {
+    lines = lines.filter((line, index) => index === 0 || !shouldStrip(line, options));
+    lines = lines.map(line => redact(line, options));
+  } else {
+    lines = lines.map(line => redact(line, options));
+  }
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  if (!frames) lines = lines.filter((line, index) => index === 0 || !shouldStrip(line, options));
+  return lines;
+}
+
+export function processStackString(
+  stack: string,
+  options: NormalizedErrorStackOptions
+): string {
+  return processLines(stack, options, false).join('\
');
+}
+
+export function processStackFrames(
+  stack: string,
+  options: NormalizedErrorStackOptions
+): Array<{ raw: string }> {
+  return processLines(stack, options, true).map(raw => ({ raw }));
